_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


   float pixelDistance   = 4;
   float motionStrength  = 4;

   float diffusionFactor = 1;
   float decay           = -0.01 + GetPixel(vUv).x*0;

   vec2 uv_y = mix(vUvOriginal,vUv,1);
   vec2 dither_uv = vUv*uTexSize.xy*texsize_noise_lq.zw*diffusionFactor;

   vec2 d = uTexSize.zw*pixelDistance;
   float1 dx = ( 2*GetBlur1(uv_y + vec2(1,0)*d) - 2*GetBlur1(uv_y-vec2(1,0)*d) ).y*0.5;
   float1 dy = ( 2*GetBlur1(uv_y + vec2(0,1)*d) - 2*GetBlur1(uv_y-vec2(0,1)*d) ).y*0.5;

   vec2 my_uv = uv_y + vec2(dx,dy)*uTexSize.zw*motionStrength;

   ret.y = texture( sampler_fw_main, clamp01(my_uv)).y;

   ret.y += (ret - GetBlur1(uv_y)).y*0.025 + decay;


   ret.y += (texture(sampler_noise_lq, dither_uv).y-0.5)*0.02;

/********************************************************************************************************/

   dx = ( 2*GetBlur1(uv_y + vec2(1,0)*d) - 2*GetBlur1(uv_y-vec2(1,0)*d) ).z*0.5;
   dy = ( 2*GetBlur1(uv_y + vec2(0,1)*d) - 2*GetBlur1(uv_y-vec2(0,1)*d) ).z*0.5;

   my_uv = uv_y - vec2(dx,dy)*uTexSize.zw*motionStrength;

   ret.z = GetPixel(my_uv).z - ret.y*0.01 + 0.004;
   ret.z += (texture(sampler_noise_lq, dither_uv).y-0.5)*0.01;


/********************************************************************************************************/

   dx = (2*GetBlur1(vUv+d*vec2(1,0))-2*GetBlur1(vUv+d*vec2(-1,0)) ).x*0.5;
   dy = (2*GetBlur1(vUv+d*vec2(0,1))-2*GetBlur1(vUv+d*vec2(0,-1)) ).x*0.5;

   vec2 d_red = +vec2(dx,dy)*uTexSize.zw;

   ret.x = maxNeumann(vUv-d_red*2.5).x + (GetPixel(vUv+d_red*4).x - GetBlur1(vUv + d_red*4).x)*0.206 - 0.09;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 d = uTexSize.zw;
    vec3 dx = ( GetPixel(vUv+vec2(1,0)*d)-GetPixel(vUv-vec2(1,0)*d) );
    vec3 dy = ( GetPixel(vUv+vec2(0,1)*d)-GetPixel(vUv-vec2(0,1)*d) );
vec2 dz = vec2(dx.y,dy.y)*3;

d = uTexSize.zw*2;
dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

dz +=vec2(dx.y,dy.y);

vec3 bg = pow(length(dz)*0.8+0,0.7) + GetBlur2(vUv).y*0.4-0.1;

ret = bg*vec3(0.3,0.5,0.7);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((dz.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;
ret = mix(ret,vec3(0.2,0.1,0),GetPixel(vUv + vec2(dx.x,dy.x)*uTexSize.zw*18).x*6);
ret = mix(ret,1,GetPixel(vUv).z);
ret=1-ret;

  fragColor = ret;
}
